# LLM 配置  
config_list $=$ [{'model': 'gpt-4.1-mini'，'api_key': 'YOUR_OPENAI_API_KEY'，}  
]  
# 1. 创建 Coder Agent（代码编写者）  
coder $=$ autogen.AssistantAgent(name "Coder"，llm_config={"config_list": config_list}  
)

# 3. 创建用户代理，用于发起任务和执⾏代码  
user_proxy $=$ autogen.UserProxyAgent(name "UserProxy"，human_input_mod $\vDash$ "NEVER"， # 在这个例⼦中，我们让它全自动运⾏max_consecutive_auto_reply=5，code_execution_config={"work_dir": "coding_project"} # 指定代码执⾏目录  
)

# 4. 组建团队并执⾏任务   
tech_trends_crew $=$ Crew( agents=[market_analyst， content_writer]， tasks=[task_analysis， task_writing]， process=Process.sequential # 按顺序执⾏   
)   
if name $\mathrel { = }  { \mathrm { \cdot } }  { \mathrm { m a i n } }$ ': result $=$ tech_trends_crew.kickoff() print("######################") print(result)
